PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?university ?universityLabel WHERE {
  VALUES ?university {
    wd:Q11381 wd:Q11236 wd:Q8692 wd:Q3071 wd:Q55782 wd:Q15249 wd:Q3503 wd:Q6664
  }
  ?university wdt:P38 ?president .
  ?president wdt:P21 wd:Q6581072 .
  ?university rdfs:label ?universityLabel .
  FILTER(langMatches(lang(?universityLabel) , 'en'))
}

